PRAGMA foreign_keys=ON;
CREATE TABLE IF NOT EXISTS user_profile(id TEXT PRIMARY KEY,name TEXT NOT NULL,age INTEGER,height_cm REAL,weight_kg REAL,sex TEXT,goal TEXT,target_weight_kg REAL,activity_level TEXT,training_days_per_week INTEGER,daily_calorie_target INTEGER DEFAULT 0,protein_target_g REAL DEFAULT 0,carbs_target_g REAL DEFAULT 0,fat_target_g REAL DEFAULT 0,water_target_l REAL DEFAULT 0,food_preferences TEXT,foods_to_avoid TEXT,allergies TEXT,available_equipment TEXT,training_level TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS workout_plans(id TEXT PRIMARY KEY,user_profile_id TEXT REFERENCES user_profile(id),name TEXT NOT NULL,goal TEXT,level TEXT,days_per_week INTEGER,duration_minutes INTEGER,equipment TEXT,priority_muscles TEXT,avoid_muscles TEXT,limitations TEXT,ai_generated INTEGER DEFAULT 0,active INTEGER DEFAULT 0,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS workout_days(id TEXT PRIMARY KEY,workout_plan_id TEXT NOT NULL REFERENCES workout_plans(id) ON DELETE CASCADE,day_of_week INTEGER NOT NULL,order_index INTEGER DEFAULT 0,title TEXT NOT NULL,focus TEXT,notes TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS exercises(id TEXT PRIMARY KEY,name TEXT NOT NULL,category TEXT,primary_muscle TEXT NOT NULL,secondary_muscles TEXT,equipment TEXT,difficulty TEXT,technical_notes TEXT,image_url TEXT,image_source TEXT,ai_image_prompt TEXT,license TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS workout_exercises(id TEXT PRIMARY KEY,workout_day_id TEXT NOT NULL REFERENCES workout_days(id) ON DELETE CASCADE,exercise_id TEXT NOT NULL REFERENCES exercises(id),order_index INTEGER DEFAULT 0,sets INTEGER NOT NULL,reps TEXT NOT NULL,rest_seconds INTEGER DEFAULT 60,tempo TEXT,progression_note TEXT,notes TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS workout_logs(id TEXT PRIMARY KEY,workout_plan_id TEXT REFERENCES workout_plans(id),workout_day_id TEXT REFERENCES workout_days(id),workout_date TEXT NOT NULL,status TEXT DEFAULT 'in_corso',completion_percent REAL DEFAULT 0,started_at TEXT,finished_at TEXT,notes TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP,UNIQUE(workout_day_id,workout_date));
CREATE TABLE IF NOT EXISTS exercise_logs(id TEXT PRIMARY KEY,workout_log_id TEXT NOT NULL REFERENCES workout_logs(id) ON DELETE CASCADE,workout_exercise_id TEXT REFERENCES workout_exercises(id),exercise_id TEXT NOT NULL REFERENCES exercises(id),completed INTEGER DEFAULT 0,weight_kg REAL,reps_done TEXT,sets_done INTEGER,rpe REAL,pain_note TEXT,notes TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP,UNIQUE(workout_log_id,workout_exercise_id));
CREATE TABLE IF NOT EXISTS diet_plans(id TEXT PRIMARY KEY,user_profile_id TEXT REFERENCES user_profile(id),name TEXT NOT NULL,source_pdf_import_id TEXT,active INTEGER DEFAULT 0,daily_calorie_target INTEGER,protein_target_g REAL,carbs_target_g REAL,fat_target_g REAL,notes TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS diet_days(id TEXT PRIMARY KEY,diet_plan_id TEXT NOT NULL REFERENCES diet_plans(id) ON DELETE CASCADE,day_of_week INTEGER NOT NULL,title TEXT,notes TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS food_items(id TEXT PRIMARY KEY,name TEXT NOT NULL,brand TEXT,default_quantity REAL DEFAULT 100,default_unit TEXT DEFAULT 'g',calories_per_100 REAL,protein_per_100_g REAL,carbs_per_100_g REAL,fat_per_100_g REAL,fiber_per_100_g REAL,water_per_100_ml REAL,source TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS planned_meals(id TEXT PRIMARY KEY,diet_day_id TEXT NOT NULL REFERENCES diet_days(id) ON DELETE CASCADE,food_item_id TEXT REFERENCES food_items(id),order_index INTEGER DEFAULT 0,meal_type TEXT NOT NULL,name TEXT NOT NULL,quantity REAL NOT NULL,unit TEXT NOT NULL,calories REAL DEFAULT 0,protein_g REAL DEFAULT 0,carbs_g REAL DEFAULT 0,fat_g REAL DEFAULT 0,fiber_g REAL DEFAULT 0,water_l REAL DEFAULT 0,notes TEXT,status TEXT DEFAULT 'previsto',created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS eaten_meals(id TEXT PRIMARY KEY,meal_date TEXT NOT NULL,planned_meal_id TEXT REFERENCES planned_meals(id),food_item_id TEXT REFERENCES food_items(id),meal_type TEXT,name TEXT NOT NULL,quantity REAL NOT NULL,unit TEXT NOT NULL,calories REAL DEFAULT 0,protein_g REAL DEFAULT 0,carbs_g REAL DEFAULT 0,fat_g REAL DEFAULT 0,fiber_g REAL DEFAULT 0,water_l REAL DEFAULT 0,status TEXT DEFAULT 'mangiato',source TEXT DEFAULT 'manual',confidence REAL,notes TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP,UNIQUE(planned_meal_id,meal_date));
CREATE TABLE IF NOT EXISTS nutrition_logs(id TEXT PRIMARY KEY,log_date TEXT NOT NULL UNIQUE,calories REAL DEFAULT 0,protein_g REAL DEFAULT 0,carbs_g REAL DEFAULT 0,fat_g REAL DEFAULT 0,fiber_g REAL DEFAULT 0,water_l REAL DEFAULT 0,notes TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS body_metrics(id TEXT PRIMARY KEY,metric_date TEXT NOT NULL,weight_kg REAL,waist_cm REAL,chest_cm REAL,arm_cm REAL,thigh_cm REAL,body_fat_percent REAL,sleep_hours REAL,steps INTEGER,notes TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS notifications(id TEXT PRIMARY KEY,type TEXT NOT NULL,title TEXT NOT NULL,body TEXT NOT NULL,time_of_day TEXT NOT NULL,frequency TEXT DEFAULT 'daily',enabled INTEGER DEFAULT 1,custom_payload TEXT,last_sent_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS push_subscriptions(id TEXT PRIMARY KEY,endpoint TEXT NOT NULL UNIQUE,p256dh TEXT NOT NULL,auth TEXT NOT NULL,user_agent TEXT,enabled INTEGER DEFAULT 1,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS app_settings(id TEXT PRIMARY KEY,key TEXT NOT NULL UNIQUE,value TEXT,value_type TEXT DEFAULT 'string',created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS ai_extractions(id TEXT PRIMARY KEY,type TEXT NOT NULL,input_text TEXT,output_json TEXT NOT NULL,provider TEXT,model TEXT,confidence REAL,status TEXT DEFAULT 'draft',reviewed_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS pdf_imports(id TEXT PRIMARY KEY,file_name TEXT NOT NULL,file_hash TEXT,raw_text TEXT,extracted_json TEXT,status TEXT DEFAULT 'uploaded',error_message TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS idx_workout_logs_date ON workout_logs(workout_date); CREATE INDEX IF NOT EXISTS idx_eaten_meals_date ON eaten_meals(meal_date); CREATE INDEX IF NOT EXISTS idx_body_metrics_date ON body_metrics(metric_date);